import React from 'react'
import { Link } from 'react-router-dom'

export default function NotFound() {
  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      height: '100vh',
      textAlign: 'center',
      padding: '20px',
      background: '#0b1222'
    }}>
      <h1 style={{ fontSize: '120px', margin: 0, color: '#4895ef' }}>404</h1>
      <h2 style={{ fontSize: '24px', color: '#e2ecf7', marginBottom: '16px' }}>Página Não Encontrada</h2>
      <p style={{ color: '#7b96b8', marginBottom: '32px', maxWidth: '400px' }}>
        A página que você está procurando não existe ou foi movida para um novo endereço.
      </p>
      <Link 
        to="/dashboard" 
        style={{
          padding: '12px 24px',
          background: '#4895ef',
          color: '#fff',
          borderRadius: '8px',
          fontWeight: 600,
          transition: 'all 0.2s ease'
        }}
      >
        Voltar para o Dashboard
      </Link>
    </div>
  )
}
